namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast, Yogurt, Tikka spice mix, Onion, Garlic, Ginger, Tomato sauce, Heavy cream, Rice", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and simmer.\n5. Stir in cream, add chicken.\n6. Serve over basmati rice.", AverageRating = 4.8, RatingCount = 24 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheddar cheese, Sour cream, Salsa", Steps = "1. Brown ground beef in skillet.\n2. Add taco seasoning and water, simmer.\n3. Warm tortillas in dry pan.\n4. Assemble tacos with meat and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract", Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs and sugar until fluffy.\n3. Fold chocolate mixture into eggs.\n4. Add flour and vanilla.\n5. Pour into greased ramekins.\n6. Bake at 425°F for 12 minutes.\n7. Invert onto plate and serve immediately.", AverageRating = 4.9, RatingCount = 31 },
        new Recipe { Id = 5, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Green onions, Peanuts, Tamarind paste, Fish sauce, Sugar, Lime", Steps = "1. Soak rice noodles in warm water.\n2. Make sauce: tamarind, fish sauce, sugar.\n3. Stir-fry shrimp until pink, set aside.\n4. Scramble eggs in wok.\n5. Add noodles and sauce, toss.\n6. Add shrimp, sprouts, and onions.\n7. Serve with peanuts and lime.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan cheese, Croutons, Caesar dressing, Lemon, Anchovy paste, Garlic", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: anchovy paste, garlic, lemon, olive oil.\n3. Toss lettuce with dressing.\n4. Add shaved parmesan and croutons.\n5. Season with black pepper.", AverageRating = 4.0, RatingCount = 6 },
    };

    private readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Classic pasta, pizza, and Mediterranean flavors", Icon = "🍕" },
        new RecipeCategory { Name = "Indian", Description = "Rich curries, aromatic spices, and vibrant dishes", Icon = "🍛" },
        new RecipeCategory { Name = "Mexican", Description = "Bold flavors with fresh salsas and tortillas", Icon = "🌮" },
        new RecipeCategory { Name = "Desserts", Description = "Sweet treats and indulgent baked goods", Icon = "🍰" },
        new RecipeCategory { Name = "Asian", Description = "Stir-fries, noodles, and umami-rich dishes", Icon = "🍜" },
        new RecipeCategory { Name = "Salads", Description = "Fresh, healthy, and colorful combinations", Icon = "🥗" },
    };

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
        }
    }
}

