@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@CategoryName Recipes</PageTitle>

<h2>@CategoryName Recipes</h2>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Any())
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted mb-1">
                            ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-sm btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h2>@Recipe.Title</h2>
    <p class="text-muted">⭐ @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>

    <div class="row">
        <div class="col-md-8">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <div class="card-body">
                    <ul class="mb-0">
                        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                        {
                            <li>@ingredient</li>
                        }
                    </ul>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header"><strong>Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p class="mb-1">@step</p>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <StarRating RecipeId="Recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<h2>Submit a Recipe</h2>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "@NewRecipe.Title" has been submitted successfully.
        <a href="category/@NewRecipe.Category">View in @NewRecipe.Category category</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="NewRecipe" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="NewRecipe.Title" placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="NewRecipe.Category">
                        <option value="">-- Select a category --</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat.Name">@cat.Name</option>
                        }
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="NewRecipe.Ingredients" placeholder="Comma-separated list of ingredients" />
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps</label>
                    <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="NewRecipe.Steps" placeholder="Step-by-step instructions (one step per line)" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private Recipe NewRecipe { get; set; } = new();
    private bool Submitted { get; set; }

    private void HandleSubmit()
    {
        if (!string.IsNullOrWhiteSpace(NewRecipe.Title) &&
            !string.IsNullOrWhiteSpace(NewRecipe.Category))
        {
            RecipeService.AddRecipe(NewRecipe);
            Submitted = true;
        }
    }
}

@using RecipeCommunity.Services
@rendermode InteractiveServer

<div class="card">
    <div class="card-header"><strong>Rate this Recipe</strong></div>
    <div class="card-body text-center">
        <div style="font-size: 2rem; cursor: pointer;">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <span @onclick="() => Rate(star)"
                      @onmouseover="() => HoverRating = star"
                      @onmouseout="() => HoverRating = 0"
                      style="color: @(star <= DisplayRating ? "gold" : "#ccc");">
                    ★
                </span>
            }
        </div>
        @if (UserRating > 0)
        {
            <p class="mt-2 text-success">You rated this @UserRating out of 5 stars!</p>
        }
        else
        {
            <p class="mt-2 text-muted">Click a star to rate</p>
        }
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private int UserRating { get; set; }
    private int HoverRating { get; set; }

    private int DisplayRating => HoverRating > 0 ? HoverRating : UserRating;

    private void Rate(int stars)
    {
        UserRating = stars;
        RecipeService.RateRecipe(RecipeId, stars);
    }
}

